


/** Creates a randomized UUID string. (May not be cryptographically secure.) */
export function createRandomUUID(): string {
    return (typeof crypto !== 'undefined') ? crypto.randomUUID() : createInsecureRandomUUID();
}


/** Creates a UUID(-ish) string without using the `crypto` API. Not cryptographically secure! */
export function createInsecureRandomUUID(): string {
    const parts: string[] = [];
    for (let i = 0; i < 4; i++) {
        const r = Math.round(Math.abs(Math.random() * (1 << 31) * 2));
        parts.push( r.toString(16).padStart(8, '0') );
    }
    return parts.join("");
}
